queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?scripts a :Scripts .
    ?scripts p:Title ?title .
    ?scripts p:Deadline ?deadline_f .
    FILTER(STR(?deadline_f) = "21.04.03")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?editors a :Editors .
    ?editors p:name ?name .
    ?editors p:Deadline ?deadline_f .
    FILTER(STR(?deadline_f) = "21.04.03")
    BIND(?name AS ?o0)
  }
}

